const t={"ec2.public_ip":{title:"EC2 Instance Has Public IP",what:"One or more EC2 instances have a public IP address directly assigned.",why:"Publicly reachable instances expand your attack surface. Any open port becomes externally accessible.",fix:["Place instances behind an Application Load Balancer (ALB) or NAT Gateway.",'Remove the public IP by disabling "Auto-assign public IP" in the subnet settings.',"Restrict Security Group inbound rules to known IP ranges only."],docs:"https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/using-instance-addressing.html",severity:"medium"},"ec2.vulnerable_ami":{title:"EC2 Using Vulnerable or Deprecated AMI",what:"Instances are running on AMIs that are outdated, deprecated, or have known CVEs.",why:"Unpatched AMIs are a common initial access vector in cloud breaches.",fix:["Build a new AMI from the latest Amazon Linux 2023 / Ubuntu 22.04 LTS base.","Enable EC2 Image Builder to auto-refresh AMIs on a schedule.","Replace running instances with new ones using the updated AMI."],docs:"https://docs.aws.amazon.com/imagebuilder/latest/userguide/what-is-image-builder.html",severity:"high"},"ec2.missing_tags":{title:"EC2 Instance Missing Required Tags",what:"Instances are missing required tags (e.g. Owner, Environment, CostCenter).",why:"Missing tags make cost attribution, incident response, and compliance auditing difficult.",fix:["Define a tagging policy using AWS Organizations Tag Policies.",'Use AWS Config rule "required-tags" to enforce tagging compliance.',"Apply tags via IaC (Terraform/CloudFormation) to all new resources."],docs:"https://docs.aws.amazon.com/tag-editor/latest/userguide/tagging.html",severity:"low"},"s3.public_access":{title:"S3 Bucket Publicly Accessible",what:"S3 bucket has public access enabled — either via ACL, bucket policy, or missing Block Public Access settings.",why:"Public S3 buckets are responsible for some of the largest data breaches. Sensitive data can be read or overwritten by anyone.",fix:['Enable "Block all public access" on the bucket in the AWS Console or via CLI.','Remove any ACL grants to "Everyone" or "Any authenticated AWS user".','Review bucket policy for `"Principal": "*"` statements and restrict them.',"Use AWS Macie to scan for sensitive data in at-risk buckets."],docs:"https://docs.aws.amazon.com/AmazonS3/latest/userguide/access-control-block-public-access.html",severity:"critical"},"s3.no_encryption":{title:"S3 Bucket Not Encrypted at Rest",what:"Server-side encryption (SSE) is not enabled on this bucket.",why:"Without encryption at rest, bucket data is readable if storage is physically compromised.",fix:["Enable SSE-S3 (AES-256) or SSE-KMS on the bucket.","Use a bucket policy to deny `s3:PutObject` requests without `x-amz-server-side-encryption`.","Prefer SSE-KMS with a customer-managed key for additional access control."],docs:"https://docs.aws.amazon.com/AmazonS3/latest/userguide/serv-side-encryption.html",severity:"high"},"s3.no_versioning":{title:"S3 Bucket Versioning Disabled",what:"Object versioning is not enabled, so deleted or overwritten objects cannot be recovered.",why:"Without versioning, ransomware or accidental deletion permanently destroys data.",fix:["Enable versioning on the bucket.","Configure lifecycle rules to expire old versions and control storage costs.","Enable MFA Delete for buckets containing critical data."],docs:"https://docs.aws.amazon.com/AmazonS3/latest/userguide/Versioning.html",severity:"medium"},"iam.wildcard_action":{title:"IAM Policy Grants Wildcard Actions (*)",what:'An IAM policy contains `"Action": "*"` granting unrestricted permissions.',why:"Wildcard actions violate least-privilege principle and allow privilege escalation.",fix:['Replace `"Action": "*"` with only the specific actions the role needs.',"Use AWS IAM Access Analyzer to generate least-privilege policies from CloudTrail.","Regularly review and prune unused permissions with IAM Access Advisor."],docs:"https://docs.aws.amazon.com/IAM/latest/UserGuide/best-practices.html#grant-least-privilege",severity:"critical"},"iam.admin_policy":{title:"IAM User or Role Has Admin Policy Attached",what:"AdministratorAccess or a similar all-encompassing policy is attached.",why:"Admin accounts are high-value targets. Compromise leads to full account takeover.",fix:["Remove AdministratorAccess and replace with scoped policies.","Use IAM roles with short-lived credentials (STS) instead of long-term admin keys.","Enable MFA on all admin accounts.","Use AWS Organizations SCPs to restrict admin actions at the org level."],docs:"https://docs.aws.amazon.com/IAM/latest/UserGuide/access_policies_job-functions.html",severity:"critical"},"iam.unused_keys":{title:"IAM Access Key Unused for 90+ Days",what:"Long-lived access keys that have not been used in over 90 days still exist.",why:"Unused credentials are a dormant risk — if leaked, attackers can use them unnoticed.",fix:["Rotate or delete access keys unused for more than 90 days.","Use IAM roles instead of long-term access keys wherever possible.","Enable AWS Credential Reports to regularly audit key usage."],docs:"https://docs.aws.amazon.com/IAM/latest/UserGuide/id_credentials_access-keys.html",severity:"high"},"sg.ssh_open":{title:"SSH Port 22 Open to the World (0.0.0.0/0)",what:"Security group allows inbound SSH (port 22) from any IP address.",why:"Open SSH is constantly scanned and brute-forced by automated bots across the internet.",fix:["Restrict SSH to your office/VPN IP ranges only.","Remove direct SSH access entirely — use AWS Systems Manager Session Manager instead.","If SSH is needed, place it behind a bastion host with strict security group rules."],docs:"https://docs.aws.amazon.com/systems-manager/latest/userguide/session-manager.html",severity:"critical"},"sg.rdp_open":{title:"RDP Port 3389 Open to the World (0.0.0.0/0)",what:"Security group allows inbound RDP (port 3389) from any IP address.",why:"Open RDP is one of the most common ransomware entry points.",fix:["Restrict RDP to VPN or specific IP ranges only.","Use AWS Systems Manager Fleet Manager for remote desktop instead of direct RDP.","Enable Network Access Control Lists (NACLs) as a secondary layer."],docs:"https://docs.aws.amazon.com/systems-manager/latest/userguide/fleet-rdp.html",severity:"critical"},"sg.all_traffic":{title:"Security Group Allows All Inbound Traffic",what:"A security group rule allows all ports and protocols from any source.",why:"This effectively disables the firewall, exposing every running service to the internet.",fix:["Replace the open rule with specific port/protocol rules for only what is needed.","Audit each running service and only allow its specific port.","Use VPC Flow Logs to understand actual traffic before tightening rules."],docs:"https://docs.aws.amazon.com/vpc/latest/userguide/vpc-security-groups.html",severity:"critical"},"rds.publicly_accessible":{title:"RDS Database Publicly Accessible",what:'The RDS instance has the "Publicly Accessible" flag set to true.',why:"A publicly accessible database can be discovered and attacked from the internet.",fix:['Set "Publicly Accessible" to false — databases should only be in private subnets.',"Use a bastion host or AWS Systems Manager for administrative access.","Ensure the DB is in a private VPC subnet with no internet gateway route."],docs:"https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_VPC.WorkingWithRDSInstanceinaVPC.html",severity:"critical"},"rds.no_encryption":{title:"RDS Database Storage Not Encrypted",what:"The RDS instance does not have storage encryption enabled.",why:"Unencrypted database storage can expose sensitive data if snapshots or storage are compromised.",fix:["Enable encryption by creating a new encrypted snapshot and restoring to a new instance.","Note: encryption cannot be enabled on a running instance — a snapshot restore is required.","Use a KMS customer-managed key for additional control over key rotation."],docs:"https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/Overview.Encryption.html",severity:"high"},"lambda.hardcoded_secret":{title:"Hardcoded Secret Detected in Lambda Function",what:"Environment variables or function code contains what appears to be a hardcoded secret, API key, or password.",why:"Hardcoded credentials are exposed to anyone with Lambda describe/list access and are difficult to rotate.",fix:["Move secrets to AWS Secrets Manager or Parameter Store (SecureString).","Update the Lambda function to fetch secrets at runtime using the AWS SDK.","Revoke and rotate any exposed credentials immediately.","Use AWS Macie to scan for additional exposed secrets."],docs:"https://docs.aws.amazon.com/secretsmanager/latest/userguide/lambda-functions.html",severity:"critical"},"lambda.timeout":{title:"Lambda Function Has Excessive Timeout",what:"The Lambda function timeout is set to the maximum (15 minutes) without justification.",why:"Excessively long timeouts increase cost from runaway invocations and mask performance issues.",fix:["Set the timeout to the 95th percentile of expected execution time + 30% buffer.","Use CloudWatch Metrics to analyze actual p99 duration.","Add dead-letter queues (DLQ) for failed invocations."],docs:"https://docs.aws.amazon.com/lambda/latest/dg/configuration-timeout.html",severity:"low"},"cloudtrail.disabled":{title:"CloudTrail Not Enabled or Not Multi-Region",what:"CloudTrail is either disabled or only logging in a single region.",why:"Without CloudTrail you have no audit log of API calls — impossible to detect breaches or do forensics.",fix:["Enable CloudTrail with multi-region logging.","Enable CloudTrail log file validation to detect tampering.","Deliver logs to a separate S3 bucket in a dedicated security account.","Set up CloudWatch Alarms for suspicious CloudTrail events."],docs:"https://docs.aws.amazon.com/awscloudtrail/latest/userguide/cloudtrail-create-and-update-a-trail.html",severity:"critical"},"ebs.unencrypted":{title:"EBS Volume Not Encrypted",what:"One or more EBS volumes do not have encryption at rest enabled.",why:"Unencrypted EBS volumes can expose data if snapshots are shared or volumes are detached.",fix:["Enable EBS default encryption at the account level so all new volumes are encrypted.","For existing volumes: create an encrypted snapshot and restore to a new encrypted volume.","Use KMS customer-managed keys for stricter access control."],docs:"https://docs.aws.amazon.com/AWSEC2/latest/UserGuide/EBSEncryption.html",severity:"high"},"eks.public_endpoint":{title:"EKS API Server Endpoint is Publicly Accessible",what:"The EKS cluster API server endpoint is accessible from the public internet.",why:"A public Kubernetes API server is a prime target for credential theft and cluster takeover.",fix:["Restrict API server access to specific CIDR blocks (your office/VPN).","Enable the private endpoint and disable the public endpoint entirely.","Ensure RBAC is configured with least-privilege roles."],docs:"https://docs.aws.amazon.com/eks/latest/userguide/cluster-endpoint.html",severity:"high"},"guardduty.disabled":{title:"AWS GuardDuty Not Enabled",what:"GuardDuty threat detection is not enabled in this region.",why:"Without GuardDuty, malicious activity (crypto mining, credential exfiltration, port scanning) goes undetected.",fix:["Enable GuardDuty in all active regions.","Enable GuardDuty at the AWS Organizations level to cover all accounts.","Configure SNS notifications or EventBridge rules for high-severity findings."],docs:"https://docs.aws.amazon.com/guardduty/latest/ug/guardduty_settingup.html",severity:"high"},"kms.no_rotation":{title:"KMS Key Auto-Rotation Disabled",what:"Customer-managed KMS keys do not have automatic key rotation enabled.",why:"Without rotation, a compromised key provides indefinite access to encrypted data.",fix:["Enable automatic annual key rotation in KMS key settings.","AWS rotates only the key material — the key ID remains the same, no re-encryption needed."],docs:"https://docs.aws.amazon.com/kms/latest/developerguide/rotate-keys.html",severity:"medium"},"vpc.default_in_use":{title:"Default VPC Is In Use",what:"Resources are deployed in the default VPC which has permissive settings.",why:"Default VPCs allow all instances to have public IPs and have open inter-instance communication.",fix:["Create a custom VPC with private subnets and a NAT Gateway.","Migrate workloads from the default VPC to the custom VPC.","Delete the default VPC from all regions once workloads are migrated."],docs:"https://docs.aws.amazon.com/vpc/latest/userguide/default-vpc.html",severity:"medium"},"vpc.no_flow_logs":{title:"VPC Flow Logs Not Enabled",what:"VPC Flow Logs are not configured for network traffic monitoring.",why:"Without flow logs, you cannot detect anomalous traffic, data exfiltration, or port scanning.",fix:["Enable VPC Flow Logs and deliver to CloudWatch Logs or S3.","Set up CloudWatch Metric Filters to alert on suspicious traffic patterns."],docs:"https://docs.aws.amazon.com/vpc/latest/userguide/flow-logs.html",severity:"medium"},"alb.no_waf":{title:"Load Balancer Has No WAF Web ACL",what:"The Application Load Balancer does not have a WAF Web ACL attached.",why:"Without WAF, common web attacks (SQL injection, XSS, DDoS) reach your application directly.",fix:["Create a WAF Web ACL with AWS Managed Rule Groups (Core Rule Set, Known Bad Inputs).","Associate the Web ACL with the ALB.","Enable AWS Shield Advanced for DDoS protection on critical ALBs."],docs:"https://docs.aws.amazon.com/waf/latest/developerguide/waf-chapter.html",severity:"high"},"alb.no_access_logs":{title:"ALB Access Logging Disabled",what:"Access logs are not enabled for the Application Load Balancer.",why:"Without access logs, you cannot investigate request patterns, attacks, or performance issues.",fix:["Enable access logging on the ALB and point it to an S3 bucket.","Set a lifecycle policy on the S3 bucket to retain logs for at least 90 days."],docs:"https://docs.aws.amazon.com/elasticloadbalancing/latest/application/load-balancer-access-logs.html",severity:"medium"},"dynamodb.no_pitr":{title:"DynamoDB Point-in-Time Recovery (PITR) Disabled",what:"PITR is not enabled, meaning accidental data loss cannot be recovered.",why:"Without PITR, accidental deletes or table corruption result in permanent data loss.",fix:["Enable PITR on all DynamoDB tables holding important data.","Test recovery procedures at least quarterly."],docs:"https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/PointInTimeRecovery.html",severity:"medium"},"ecr.critical_cve":{title:"Container Image Has Critical CVEs",what:"ECR image scan found critical or high severity CVEs in container images.",why:"Container vulnerabilities can be exploited for container escape, privilege escalation, or data theft.",fix:["Update the base image to the latest version.","Rebuild and push a patched image immediately.","Enable scan-on-push to catch vulnerabilities before they reach production.","Use Amazon Inspector for continuous container vulnerability monitoring."],docs:"https://docs.aws.amazon.com/AmazonECR/latest/userguide/image-scanning.html",severity:"critical"},"ecr.no_scan_on_push":{title:"ECR Repository Has Scan-on-Push Disabled",what:"Container images are pushed to ECR without being automatically scanned for vulnerabilities.",why:"Unscanned images may contain known CVEs that could have been caught at build time.",fix:["Enable scan-on-push for all ECR repositories.","Configure EventBridge rules to alert on critical scan findings."],docs:"https://docs.aws.amazon.com/AmazonECR/latest/userguide/image-scanning.html",severity:"high"}};function r(e){if(!e)return null;const a=(e.rule_id||"").toLowerCase(),s=(e.resource_type||"").toLowerCase();if(a&&t[a])return t[a];for(const i of Object.keys(t)){const[n]=i.split(".");if(s&&s.startsWith(n))return t[i]}const o=(e.severity||"medium").toLowerCase();return{title:e.title||"Security Finding",what:e.title||"A security issue was detected in your cloud environment.",why:"This finding may indicate a misconfiguration or security gap that could be exploited.",fix:["Review the affected resource and apply the principle of least privilege.","Consult the AWS Security Best Practices documentation for this service.","Consider enabling AWS Config rules to automatically detect and alert on this issue."],docs:"https://docs.aws.amazon.com/security/",severity:o}}const c={critical:0,high:1,medium:2,low:3,info:4};export{t as R,c as S,r as g};
